 7	use std::time::{SystemTime, UNIX_EPOCH};
 8	
 9	const TEMP_DIR_ATTEMPTS: u32 = 32;
10	
11	#[derive(Debug)]
12	pub struct TempStateHarness {
13	    root: PathBuf,
14	}
15	
16	impl TempStateHarness {
17	    pub fn new() -> io::Result<Self> {
18	        let root = reserve_temp_root()?;
19	        Ok(Self { root })
20	    }
21	
22	    pub fn path(&self) -> &Path {
23	        &self.root
24	    }
25	}
26	
27	impl Drop for TempStateHarness {
28	    fn drop(&mut self) {
29	        let _ = fs::remove_dir_all(&self.root);
30	    }
31	}
32	
33	fn reserve_temp_root() -> io::Result<PathBuf> {
34	    let base = env::temp_dir();
35	
36	    for attempt in 0..TEMP_DIR_ATTEMPTS {
37	        let candidate = base.join(unique_temp_dir_name(attempt));
38	        match fs::create_dir(&candidate) {
39	            Ok(()) => return Ok(candidate),
40	            Err(error) if error.kind() == io::ErrorKind::AlreadyExists => continue,
41	            Err(error) => return Err(error),
42	        }
43	    }
44	
45	    Err(io::Error::new(
46	        io::ErrorKind::AlreadyExists,
47	        "failed to reserve a unique VIDA temp-state directory",
48	    ))
49	}
50	
51	fn unique_temp_dir_name(attempt: u32) -> String {
52	    let nanos = SystemTime::now()
53	        .duration_since(UNIX_EPOCH)
54	        .map(|duration| duration.as_nanos())
55	        .unwrap_or(0);
56	
57	    format!(
58	        "vida-temp-state-{}-{}-{}",
59	        std::process::id(),
60	        nanos,
61	        attempt
62	    )
63	}

